﻿@inherits LayoutComponentBase
@using sv_7f789a47ee274ab68e772367c58d80eb.Services

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Progress is not null)
            {
                <nav class="wizard-progress d-flex align-items-center gap-2 me-auto">
                    @for (var i = 0; i < WizardProgress.Steps.Length; i++)
                    {
                        var step = WizardProgress.Steps[i];
                        var stepNum = i;
                        var isActive = stepNum == Progress.CurrentStep;
                        var isCompleted = Progress.CompletedSteps.Contains(stepNum);
                        <a href="@step.Path"
                           class="badge text-decoration-none @(isActive ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary")">
                            Step @(stepNum + 1): @step.Label
                        </a>
                    }
                    <span class="ms-2 text-muted small">
                        Step @(Progress.CurrentStep + 1) of @WizardProgress.Steps.Length
                    </span>
                </nav>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }
}

