@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_7f789a47ee274ab68e772367c58d80eb.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Info</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(0, ProgressSource.CurrentValue?.CompletedSteps ?? []));
    }

    private async Task Next()
    {
        var completed = new HashSet<int>(ProgressSource.CurrentValue?.CompletedSteps ?? []) { 0 };
        await ProgressSource.NotifyChangedAsync(new WizardProgress(1, completed));
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_7f789a47ee274ab68e772367c58d80eb.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (var i = 0; i < Wizard.Jobs.Count; i++)
{
    var job = Wizard.Jobs[i];
    var index = i;
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => Wizard.Jobs.RemoveAt(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(1, ProgressSource.CurrentValue?.CompletedSteps ?? []));
    }

    private void AddJob() => Wizard.Jobs.Add(new JobEntry());

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(0, ProgressSource.CurrentValue?.CompletedSteps ?? []));
