@page "/apply/review"
@rendermode InteractiveServer
@using sv_7f789a47ee274ab68e772367c58d80eb.Services
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<h4>Personal Info</h4>
<dl class="row">
    <dt class="col-sm-3">Name</dt>
    <dd class="col-sm-9">@Wizard.Name</dd>
    <dt class="col-sm-3">Email</dt>
    <dd class="col-sm-9">@Wizard.Email</dd>
</dl>

<h4>Experience</h4>
@if (Wizard.Jobs.Count == 0)
{
    <p class="text-muted">No job entries added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th></tr>
        </thead>
        <tbody>
            @foreach (var job in Wizard.Jobs)
            {
                <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
            }
        </tbody>
    </table>
}

<h4>References</h4>
@if (Wizard.References.Count == 0)
{
    <p class="text-muted">No references added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Name</th><th>Email</th><th>Relationship</th></tr>
        </thead>
        <tbody>
            @foreach (var r in Wizard.References)
            {
                <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
            }
        </tbody>
    </table>
}

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(3, ProgressSource.CurrentValue?.CompletedSteps ?? []));
    }

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(2, ProgressSource.CurrentValue?.CompletedSteps ?? []));
        Nav.NavigateTo("/apply/references");
    }

    private async Task Submit()
    {
        var allCompleted = new HashSet<int> { 0, 1, 2, 3 };
        await ProgressSource.NotifyChangedAsync(new WizardProgress(3, allCompleted));
        // TODO: persist the application to a database here
    }
}

